# shipment webhook
# Symptom: Carrier sends duplicate delivered webhook.
#
# Fix: dedupe at the source using the carrier's event id (or a stable
# composite key) so retries/duplicates from the carrier do not produce
# duplicate customer-visible effects (notifications, refunds, etc).

_processed_event_ids = set()


def _event_key(event: dict) -> str:
    # Prefer carrier-provided unique event id; fall back to a stable composite.
    eid = event.get("event_id") or event.get("id")
    if eid:
        return f"eid:{eid}"
    return "composite:{shipment}:{status}:{ts}".format(
        shipment=event.get("shipment_id"),
        status=event.get("status"),
        ts=event.get("timestamp"),
    )


def handle_webhook(event: dict) -> dict:
    """Process a carrier webhook exactly once per event key."""
    key = _event_key(event)
    if key in _processed_event_ids:
        return {"status": "duplicate", "key": key}
    _processed_event_ids.add(key)
    # ... perform side effects (notify customer, update order, etc.) ...
    return {"status": "ok", "key": key}

